import{CacheFirst,NetworkFirst}from 'https://cdn.jsdelivr.net/npm/workbox-strategies@7/+esm';import{CacheableResponsePlugin}from 'https://cdn.jsdelivr.net/npm/workbox-cacheable-response@7/+esm';import{ExpirationPlugin}from 'https://cdn.jsdelivr.net/npm/workbox-expiration@7/+esm';import{BackgroundSyncPlugin}from 'https://cdn.jsdelivr.net/npm/workbox-background-sync@7/+esm';import{openDB}from 'https://cdn.jsdelivr.net/npm/idb@8/+esm';const CONFIG={MANIFEST_URL:'file-list.json',CACHE_NAME_PREFIX:'precache',DYNAMIC_CACHE_NAME:'dynamic-content',NETWORK_TIMEOUT_MS:3000,MAX_DYNAMIC_ENTRIES:50,DEBUG:false};const ORIGIN=self.location.origin;const log=(...args)=>CONFIG.DEBUG&&console.log('[SW]',...args);const warn=(...args)=>CONFIG.DEBUG&&console.warn('[SW]',...args);const error=(...args)=>CONFIG.DEBUG&&console.error('[SW]',...args);let dbPromise=null;let currentCacheName='';const precacheAllowList=new Map();let warmUpUrls=[];let strategiesInitialized=false;let cacheFirstHandler,networkFirstHandler,dynamicHandler;async function initDB(){if(dbPromise){return dbPromise}dbPromise=openDB('sw-custom-storage',1,{upgrade(db,oldVersion,newVersion,transaction){if(!db.objectStoreNames.contains('offline-forms')){db.createObjectStore('offline-forms',{keyPath:'id',autoIncrement:true})}if(!db.objectStoreNames.contains('prefetch-metadata')){db.createObjectStore('prefetch-metadata')}if(!db.objectStoreNames.contains('failed-retries')){db.createObjectStore('failed-retries',{keyPath:'url'})}}});return dbPromise}async function getDB(){const db=await initDB();return db}async function idbPutMetadata(url,metadata){try{const db=await getDB();await db.put('prefetch-metadata',metadata,url);log('IDB',`Stored metadata for: ${ url }`)}catch(err){error('IDB','put failed:',err)}}async function idbGetMetadata(url){try{const db=await getDB();return await db.get('prefetch-metadata',url)}catch(err){error('IDB','get failed:',err);return null}}async function idbDeleteMetadata(url){try{const db=await getDB();await db.delete('prefetch-metadata',url);log('IDB',`Deleted metadata for: ${ url }`)}catch(err){error('IDB','delete failed:',err)}}async function idbStoreFailedRequest(url,data,method='POST'){try{const db=await getDB();await db.put('failed-retries',{url,data,method,timestamp:Date.now()});log('IDB',`Stored failed request for: ${ url }`)}catch(err){error('IDB','store failed request:',err)}}async function idbGetFailedRequests(){try{const db=await getDB();return await db.getAll('failed-retries')}catch(err){error('IDB','get failed requests:',err);return[]}}async function idbDeleteFailedRequest(url){try{const db=await getDB();await db.delete('failed-retries',url);log('IDB',`Deleted failed request for: ${ url }`)}catch(err){error('IDB','delete failed request:',err)}}async function idbGetAllKeys(storeName){try{const db=await getDB();return await db.getAllKeys(storeName)}catch(err){error('IDB','get keys failed:',err);return[]}}async function idbCleanStaleMetadata(){if(!currentCacheName){warn('activate','Skipping stale IDB metadata cleanup: currentCacheName not initialized.');return}try{const allKeys=await idbGetAllKeys('prefetch-metadata');let cleaned=0;for(const key of allKeys){const meta=await idbGetMetadata(key);if(!meta){continue}if(meta.cacheName&&meta.cacheName!==currentCacheName){await idbDeleteMetadata(key);cleaned+=1}}if(cleaned>0){log('activate',`Cleaned ${ cleaned } stale IDB metadata entries.`)}}catch(err){error('IDB','Stale metadata cleanup failed:',err)}}function normalizeUrl(url){try{return new URL(url,ORIGIN).href}catch{return null}}function createCacheKey(url,revision){const parsed=new URL(url,ORIGIN);if(revision){parsed.searchParams.set('__rev',revision)}return parsed.href}async function loadManifest(){let response;try{response=await fetch(CONFIG.MANIFEST_URL,{cache:'no-cache'})}catch(e){throw new Error(`Failed to fetch manifest: Network error (${e.message })`)}if(!response.ok){throw new Error(`Failed to fetch manifest: HTTP ${response.status }`)}const manifest=await response.json();const{version,defaultRevision,groups=[],warmUp=[]}=manifest;currentCacheName=`${CONFIG.CACHE_NAME_PREFIX }-v${ version }`;warmUpUrls=warmUp.map(u=>normalizeUrl(u)).filter(Boolean);const entries=[];for(const group of groups||[]){if(group.strategy!=='precache'){continue}for(const file of group.files??[]){const revision=file.revision??defaultRevision;const normalizedUrl=normalizeUrl(file.url);if(!normalizedUrl){warn('manifest','Skipping invalid URL in manifest:',file.url);continue}const cacheKey=createCacheKey(file.url,revision);precacheAllowList.set(normalizedUrl,cacheKey);entries.push({url:file.url,cacheKey,normalizedUrl})}}log('manifest',`Loaded ${entries.length } precache entries for version ${ version }`);return entries}async function precacheAssets(){await initDB();const entries=await loadManifest();if(entries.length===0){log('install','No assets defined in manifest to precache.');return}log('install',`Starting precache: ${entries.length } assets into '${ currentCacheName }'`);const cache=await caches.open(currentCacheName);let successCount=0;let failureCount=0;const results=await Promise.allSettled(entries.map(async({url,cacheKey})=>{try{const response=await fetch(url,{cache:'no-cache'});if(!response.ok){throw new Error(`HTTP ${response.status }`)}await cache.put(cacheKey,response);await idbPutMetadata(url,{cacheKey,cacheName:currentCacheName,cachedAt:Date.now(),status:'precache'});return{success:true,url}}catch(err){return{success:false,url,error:err.message}}}));results.forEach(result=>{if(result.status==='fulfilled'&&result.value.success){successCount+=1}else{failureCount+=1;const url=result.status==='fulfilled'?result.value.url:'unknown';warn('install',`Failed to cache: ${ url }`,result.value?.error??result.reason)}});log('install',`Precache Summary: ${ successCount }/${entries.length } succeeded.`);if(failureCount===entries.length){throw new Error('CRITICAL FAILURE: All precache requests failed. Installation aborted.')}if(failureCount>0){warn('install',`${ failureCount } assets failed. Check logs for details.`)}}async function cleanupStaleCaches(){const keys=await caches.keys();const prefixPattern=new RegExp(`^${CONFIG.CACHE_NAME_PREFIX }-v\\d+$`);const validCacheNames=[currentCacheName,CONFIG.DYNAMIC_CACHE_NAME];let deletedCount=0;for(const key of keys){let shouldDelete=false;let reason='';if(prefixPattern.test(key)){if(key!==currentCacheName){shouldDelete=true;reason='Old precache version'}}else if(!validCacheNames.includes(key)){shouldDelete=true;reason='Unrecognized cache'}if(shouldDelete){log('activate',`Deleting stale cache: ${ key } (${ reason })`);await caches.delete(key);deletedCount+=1}}if(deletedCount>0){log('activate',`Cache cleanup complete. Deleted ${ deletedCount } caches.`)}await idbCleanStaleMetadata()}async function initStrategies(){if(strategiesInitialized){return}const cacheablePlugin=new CacheableResponsePlugin({statuses:[0,200]});const expirationPlugin=new ExpirationPlugin({maxEntries:CONFIG.MAX_DYNAMIC_ENTRIES,purgeOnQuotaError:true});const bgSyncPlugin=new BackgroundSyncPlugin('post-sync-queue',{maxRetentionTime:24*60,onSync:async({queue})=>{let entry;while((entry=await queue.shiftRequest())){try{await fetch(entry.request);log('bg-sync',`Replayed successfully: ${entry.request.url }`);await idbDeleteFailedRequest(entry.request.url)}catch(err){const body=await entry.request.clone().text();await idbStoreFailedRequest(entry.request.url,body,entry.request.method);await queue.unshiftRequest(entry);log('bg-sync',`Replay failed for ${entry.request.url }, re-queued.`,err.message)}}const clients=await self.clients.matchAll();for(const client of clients){client.postMessage({type:'BG_SYNC_COMPLETE'})}}});cacheFirstHandler=new CacheFirst({cacheName:currentCacheName,plugins:[cacheablePlugin]});networkFirstHandler=new NetworkFirst({cacheName:currentCacheName,networkTimeoutSeconds:Math.ceil(CONFIG.NETWORK_TIMEOUT_MS/1000),plugins:[cacheablePlugin]});dynamicHandler=new NetworkFirst({cacheName:CONFIG.DYNAMIC_CACHE_NAME,networkTimeoutSeconds:Math.ceil(CONFIG.NETWORK_TIMEOUT_MS/1000),plugins:[cacheablePlugin,expirationPlugin,bgSyncPlugin]});strategiesInitialized=true;log('init','All caching strategies initialized.')}async function warmUpCache(){if(warmUpUrls.length===0){return}log('warming',`Triggering idle warm-up for ${warmUpUrls.length } URLs`);const cache=await caches.open(currentCacheName);for(const url of warmUpUrls){const normalizedUrl=normalizeUrl(url);const cacheKey=normalizedUrl?precacheAllowList.get(normalizedUrl):normalizedUrl;const lookupKey=cacheKey||url;if(await cache.match(lookupKey)){continue}try{const response=await fetch(url,{cache:'no-cache'});if(response.ok){await cache.put(lookupKey,response);await idbPutMetadata(url,{cacheName:currentCacheName,warmedUpAt:Date.now(),status:'warmup'});log('warming',`Warmed up: ${ url }`)}else{warn('warming',`Warmup failed for ${ url }: HTTP ${response.status }`)}}catch(err){warn('warming',`Warmup network error for ${ url }:`,err.message)}}}function triggerWarmUp(){if(typeof requestIdleCallback==='function'){requestIdleCallback(warmUpCache,{timeout:5000})}else{setTimeout(warmUpCache,5000)}}self.addEventListener('install',(event)=>{event.waitUntil(precacheAssets().then(()=>{log('install','Precaching finished successfully.');return self.skipWaiting()}).catch(err=>{error('install','Installation FAILED:',err.message);throw err}))});self.addEventListener('activate',(event)=>{event.waitUntil((async()=>{await cleanupStaleCaches();log('activate','Stale cache cleanup finished.');if(self.registration.navigationPreload){await self.registration.navigationPreload.enable();log('activate','Navigation preload enabled.')}await self.clients.claim();await initStrategies();log('activate','Service Worker fully active and ready.')})())});self.addEventListener('message',async(event)=>{const{type}=event.data??{};const source=event.source;switch(type){case 'PING':{const port=event.ports[0];if(port){port.postMessage({type:'PONG'})}else{source.postMessage({type:'PONG'})}break}case 'QUERY_SYNC_STATUS':{const failed=await idbGetFailedRequests();source.postMessage({type:'SYNC_STATUS',data:{pendingCount:failed.length,items:failed}});break}case 'TRIGGER_RETRY':{const failed=await idbGetFailedRequests();for(const item of failed){try{const fetchOptions={method:item.method||'POST'};if(item.data){fetchOptions.body=item.data;fetchOptions.headers={'Content-Type':'application/json'}}const res=await fetch(item.url,fetchOptions);if(res.ok){await idbDeleteFailedRequest(item.url);log('retry',`Manual retry succeeded for ${item.url }`)}else{warn('retry',`Manual retry got HTTP ${res.status } for ${item.url }`)}}catch(err){error('retry',`Manual retry failed for ${item.url }:`,err.message)}}const remaining=await idbGetFailedRequests();source.postMessage({type:'SYNC_STATUS',data:{pendingCount:remaining.length}});break}case 'QUERY_METADATA':{const{url}=event.data??{};if(url){const meta=await idbGetMetadata(url);source.postMessage({type:'PRECACHE_METADATA',data:{url,metadata:meta}})}else{source.postMessage({type:'PRECACHE_METADATA',data:{url,metadata:null,error:'No URL provided'}})}break}}});function isNavigationRequest(request){return request.mode==='navigate'||request.headers.get('accept')?.includes('text/html')}self.addEventListener('fetch',(event)=>{if(event.request.method!=='GET'){return}if(!strategiesInitialized){log('fetch','Fetch intercepted before init, passing through.');return}if(!self.warmupTriggered){self.warmupTriggered=true;setTimeout(triggerWarmUp,2000)}const normalizedUrl=normalizeUrl(event.request.url);const cacheKey=normalizedUrl?precacheAllowList.get(normalizedUrl):null;if(cacheKey){if(isNavigationRequest(event.request)){event.respondWith(networkFirstHandler.handle({request:event.request}).catch(()=>caches.open(currentCacheName).then(cache=>cache.match(cacheKey))))}else{event.respondWith(cacheFirstHandler.handle({request:event.request}))}}else{if(isNavigationRequest(event.request)){event.respondWith(networkFirstHandler.handle({request:event.request}).catch(async()=>{const offlinePage=await caches.match('/offline.html');if(offlinePage){return offlinePage}const rootKey=precacheAllowList.get(normalizeUrl('/'));if(rootKey){const cache=await caches.open(currentCacheName);return cache.match(rootKey)}return Response.error()}))}else{event.respondWith(dynamicHandler.handle({request:event.request}))}}});
